#(parameter
        DATA_WIDTH  = 32,
        ADDR_WIDTH  = 6,
        DEPTH       = 63
    )(
        input  wire                  clk,
        input  wire                  reset,
        input  wire                  clk_en,
        input  wire                  we,
        input  wire [DATA_WIDTH-1:0] din,
        input  wire [ADDR_WIDTH-1:0] raddr,
        input  wire                  re,
        output reg  [DATA_WIDTH-1:0] dout
    );

    reg  [DATA_WIDTH-1:0] mem[0:DEPTH-2];

    integer i;
    always @(posedge clk)
    begin
        if (clk_en & we) begin
            for (i = 0; i < DEPTH - 2; i = i + 1) begin
                mem[i+1] <= mem[i];
            end
            mem[0] <= din;
        end
    end

    always @(posedge clk)
    begin
        if (reset)
            dout <= 0;
        else if (clk_en & re) begin
            dout <= mem[raddr];
        end
    end

endmodule

