    output wire [ADDR_WIDTH-1:0] out_BURST_ADDR,
    output wire [7:0]            out_BURST_LEN,
    output wire                  out_BURST_VALID,
    input  wire                  in_BURST_READY,
    output wire [ID_WIDTH-1:0]   out_CTRL_ID,
    output wire                  out_CTRL_INFO,
    output wire                  out_CTRL_VALID,
    input  wire [NUM_PORTS-1:0]  in_CTRL_READY
);

    generate
    if ((INTERLEAVE == 1) && (NUM_PORTS > 1)) begin
        SSM_in_z_silu_m_axi_burst_interleave #(
            .ID_WIDTH          (ID_WIDTH),
            .DATA_WIDTH        (DATA_WIDTH),
            .ADDR_WIDTH        (ADDR_WIDTH),
            .LEN_WIDTH         (LEN_WIDTH),
            .NUM_PORTS         (NUM_PORTS),
            .MAX_BURST_LEN     (MAX_BURST_LEN)
        ) burst_interleave (
            .clk               (clk),
            .reset             (reset),
            .clk_en            (clk_en),
            .in_REQ_ID         (in_REQ_ID),
            .in_REQ_ADDR       (in_REQ_ADDR),
            .in_REQ_LEN        (in_REQ_LEN),
            .in_REQ_VALID      (in_REQ_VALID),
            .out_REQ_READY     (out_REQ_READY),
            .out_BURST_ID      (out_BURST_ID),
            .out_BURST_ADDR    (out_BURST_ADDR),
            .out_BURST_LEN     (out_BURST_LEN),
            .out_BURST_VALID   (out_BURST_VALID),
            .in_BURST_READY    (in_BURST_READY),
            .out_CTRL_ID       (out_CTRL_ID),
            .out_CTRL_INFO     (out_CTRL_INFO),
            .out_CTRL_VALID    (out_CTRL_VALID),
            .in_CTRL_READY     (in_CTRL_READY)
        );

    end
    else begin
        SSM_in_z_silu_m_axi_burst_sequential #(
            .ID_WIDTH          (ID_WIDTH),
            .DATA_WIDTH        (DATA_WIDTH),
            .ADDR_WIDTH        (ADDR_WIDTH),
            .LEN_WIDTH         (LEN_WIDTH),
            .NUM_PORTS         (NUM_PORTS),
            .MAX_BURST_LEN     (MAX_BURST_LEN)
        ) burst_sequential (
            .clk               (clk),
            .reset             (reset),
            .clk_en            (clk_en),
            .in_REQ_ID         (in_REQ_ID),
            .in_REQ_ADDR       (in_REQ_ADDR),
            .in_REQ_LEN        (in_REQ_LEN),
            .in_REQ_VALID      (in_REQ_VALID),
            .out_REQ_READY     (out_REQ_READY),
            .out_BURST_ID      (out_BURST_ID),
            .out_BURST_ADDR    (out_BURST_ADDR),
            .out_BURST_LEN     (out_BURST_LEN),
            .out_BURST_VALID   (out_BURST_VALID),
            .in_BURST_READY    (in_BURST_READY),
            .out_CTRL_ID       (out_CTRL_ID),
            .out_CTRL_INFO     (out_CTRL_INFO),
            .out_CTRL_VALID    (out_CTRL_VALID),
            .in_CTRL_READY     (in_CTRL_READY)
        );

    end
    endgenerate

endmodule


(* DowngradeIPIdentifiedWarnings="yes" *) module SSM_in_z_silu_m_axi_burst_interleave
#(parameter
    ID_WIDTH                     = 1,
    DATA_WIDTH                   = 32,
    ADDR_WIDTH                   = 32,
    LEN_WIDTH                    = 32,
    NUM_PORTS                    = 1,
    MAX_BURST_LEN                = 16
)(
    input  wire                  clk,
    input  wire                  reset,
    input  wire                  clk_en,
    input  wire [ID_WIDTH-1:0]   in_REQ_ID,
    input  wire [ADDR_WIDTH-1:0] in_REQ_ADDR,
    input  wire [LEN_WIDTH-1:0]  in_REQ_LEN,
    input  wire                  in_REQ_VALID,
    output wire [NUM_PORTS-1:0]  out_REQ_READY,
    output wire [ID_WIDTH-1:0]   out_BURST_ID,
    output wire [ADDR_WIDTH-1:0] out_BURST_ADDR,
    output wire [7:0]            out_BURST_LEN,
    output wire                  out_BURST_VALID,
    input  wire                  in_BURST_READY,
    output wire [ID_WIDTH-1:0]   out_CTRL_ID,
    output wire                  out_CTRL_INFO,
    output wire                  out_CTRL_VALID,
    input  wire [NUM_PORTS-1:0]  in_CTRL_READY
);
//------------------------Parameter----------------------
    localparam
        PACK_WIDTH      = ID_WIDTH+ADDR_WIDTH+LEN_WIDTH,
        DATA_BYTES      = DATA_WIDTH / 8,
        ADDR_ALIGN      = log2(DATA_BYTES),
        BOUNDARY_BEATS  = {12-ADDR_ALIGN{1'b1}},
        NUM_BEAT_WIDTH  = log2(MAX_BURST_LEN);
//------------------------Task and function--------------
    function integer log2;
        input integer x;
        integer n, m;
        begin
            n = 0;
            m = 1;
            while (m < x) begin
                n = n + 1;
                m = m * 2;
            end
            log2 = n;
        end
    endfunction
//------------------------Local signal-------------------
    wire [PACK_WIDTH-1:0]       req_pack_in;
    wire [PACK_WIDTH-1:0]       req_pack_out;
    wire [ID_WIDTH-1:0]         req_id_tmp;
    wire [ADDR_WIDTH-1:0]       req_addr_tmp;
    wire [LEN_WIDTH-1:0]        req_len_tmp;

    wire                        req_full_n;
    wire                        req_empty_n;
    wire                        write_req;
    wire                        read_req;
    reg  [NUM_PORTS-1:0]        req_ready;
    wire                        next_req;

    reg  [ADDR_WIDTH - 1:0]     start_addr;
    wire [ADDR_WIDTH - 1:0]     sect_addr;
    reg  [ADDR_WIDTH - 1:0]     sect_addr_buf;
    reg  [ID_WIDTH-1:0]         req_id;
    reg  [ID_WIDTH-1:0]         req_id_buf;
    reg                         req_handling;

    reg  [11 - ADDR_ALIGN:0]    start_to_4k;
    reg  [11 - ADDR_ALIGN:0]    end_from_4k;
    wire [11 - ADDR_ALIGN:0]    sect_len;
    reg  [11 - ADDR_ALIGN:0]    sect_len_buf;
    reg  [LEN_WIDTH-1:0]        beat_len;
    reg  [LEN_WIDTH-1:0]        beat_len_buf;

    reg  [ADDR_WIDTH-13:0]      sect_cnt;
    reg  [LEN_WIDTH-13:0]       sect_total;
    reg  [LEN_WIDTH-13:0]       sect_total_buf;
    wire [LEN_WIDTH-13:0]       sect_total_tmp;
    wire                        ready_for_sect;

    wire                        single_sect;
    reg                         first_sect;
    reg                         last_sect;
    wire                        last_sect_tmp;
    reg                         last_sect_buf;
    wire                        next_sect;

    reg                         burst_valid;

    wire [ID_WIDTH-1:0]         ost_ctrl_id;
    wire                        ost_ctrl_info;
    wire                        ost_ctrl_valid;
    wire                        ost_ctrl_ready;

    wire [PACK_WIDTH-1:0]       rem_req_pack;
    reg                         rem_req_valid;
    reg  [ID_WIDTH-1:0]         rem_req_id;
    reg  [ADDR_WIDTH-1:0]       rem_req_addr;
    reg  [LEN_WIDTH-1:0]        rem_req_len;
    wire [ADDR_WIDTH-1:0]       rem_req_addr_pred;
    wire [LEN_WIDTH-1:0]        rem_req_len_pred;

//------------------------Instantiation------------------
    generate 
    if (NUM_PORTS > 2) begin
        SSM_in_z_silu_m_axi_fifo #(
            .DATA_WIDTH        (PACK_WIDTH),
            .ADDR_WIDTH        (log2(NUM_PORTS)),
            .DEPTH             (NUM_PORTS)
        ) req_buffer (
            .clk               (clk),
            .reset             (reset),
            .clk_en            (clk_en),
            .if_full_n         (req_full_n),
            .if_write          (write_req),
            .if_din            (req_pack_in),
            .if_empty_n        (req_empty_n),
            .if_read           (read_req),
            .if_dout           (req_pack_out),
            .if_num_data_valid ());
    end
    else begin
        SSM_in_z_silu_m_axi_reg_slice #(
            .DATA_WIDTH     (PACK_WIDTH)
        ) rs_req (
            .clk            (clk),
            .reset          (reset),
            .s_ready        (req_full_n),
            .s_valid        (write_req),
            .s_data         (req_pack_in),
            .m_valid        (req_empty_n),
            .m_ready        (read_req),
            .m_data         (req_pack_out));
    end
    endgenerate
        
//------------------------Body--------------------------- 
    assign out_REQ_READY = (req_full_n && ~rem_req_valid) ? req_ready : {NUM_PORTS{1'b0}};
    assign req_pack_in   = rem_req_valid ? rem_req_pack  : {in_REQ_ID, in_REQ_LEN, in_REQ_ADDR};
    assign write_req     = rem_req_valid || in_REQ_VALID;
    
    always @(posedge clk) 
    begin
        if (reset)
            req_ready <= {NUM_PORTS{1'b1}};
        else if (clk_en) begin
            if (in_REQ_VALID && req_full_n && ~rem_req_valid)
                req_ready[in_REQ_ID] = 1'b0;
            if (ost_ctrl_info && ost_ctrl_valid)
                req_ready[ost_ctrl_id] = 1'b1;
        end
    end

    assign req_id_tmp    = req_pack_out[PACK_WIDTH-1 : ADDR_WIDTH+LEN_WIDTH];
    assign req_len_tmp   = req_pack_out[ADDR_WIDTH+LEN_WIDTH-1 : ADDR_WIDTH];
    assign req_addr_tmp  = req_pack_out[ADDR_WIDTH-1 : 0];

    assign next_req      = read_req && req_empty_n;

    always @(posedge clk)
    begin
        if (reset) begin
            req_id      <= 0;
            start_addr  <= 0;
            sect_total  <= 0;
            end_from_4k <= 0;
            start_to_4k <= 0;
        end
        else if (clk_en) begin
            if(next_req) begin
                req_id      <= req_id_tmp;
                start_addr  <= {req_addr_tmp[ADDR_WIDTH-1:ADDR_ALIGN], {ADDR_ALIGN{1'b0}}}; // addr align
                sect_total  <= (req_len_tmp + req_addr_tmp[11:0]) >> 12;
                end_from_4k <= (req_addr_tmp[11:0] + req_len_tmp[11:0]) >> ADDR_ALIGN;
                start_to_4k <= BOUNDARY_BEATS - req_addr_tmp[11:ADDR_ALIGN];
            end
        end
    end

    always @(posedge clk)
    begin
        if (reset)
            req_handling <= 1'b0;
        else if (clk_en) begin
            if (next_req)
                req_handling <= 1'b1;
            else if (~req_empty_n && last_sect_tmp && next_sect)
                req_handling <= 1'b0;
        end
    end

    // 4k boundary
    assign last_sect_tmp  = single_sect || last_sect;

    assign sect_total_tmp = first_sect ? sect_total : sect_total_buf;

    assign single_sect  = (sect_total == 0);

    assign sect_addr  = (first_sect)? start_addr : {sect_cnt, {12{1'b0}}};
    assign sect_len   = single_sect                ? beat_len[11-ADDR_ALIGN:0] :
                        ( first_sect && ~last_sect)? start_to_4k :
                        (~first_sect &&  last_sect)? end_from_4k :
                                                     BOUNDARY_BEATS;
   always @(posedge clk)
    begin
        if (reset) begin
            first_sect <= 1'b0;
            last_sect <= 1'b0;
            sect_cnt <= 0;
            beat_len <= 0;
        end
        else if (clk_en) begin
            if (next_req) begin
                first_sect <= 1'b1;
                last_sect <= 1'b0;
                sect_cnt <= req_addr_tmp[ADDR_WIDTH-1:12];
                beat_len <= (req_len_tmp + req_addr_tmp[ADDR_ALIGN-1:0]) >> ADDR_ALIGN;  // beat align
            end
            else if (next_sect) begin
                first_sect <= 1'b0;
                last_sect <= (sect_total_tmp == 1);
                sect_cnt <= sect_cnt + 1;
                beat_len <= beat_len - sect_len - 1;
            end
        end
    end

    always @(posedge clk)
    begin
        if (reset) begin
            req_id_buf     <= 0;
            sect_addr_buf  <= 0;
            sect_len_buf   <= 0;
            last_sect_buf  <= 1'b0;
            beat_len_buf   <= 0;
            sect_total_buf <= 0;
        end
        else if (clk_en) begin
            if (next_sect) begin
                req_id_buf     <= req_id;
                sect_addr_buf  <= sect_addr;
                sect_len_buf   <= sect_len;
                last_sect_buf  <= last_sect_tmp;
                beat_len_buf   <= beat_len;
                sect_total_buf <= sect_total_tmp - 1;
            end
        end
    end

    assign out_CTRL_VALID     = ost_ctrl_valid;
    assign out_CTRL_INFO      = ost_ctrl_info;
    assign out_CTRL_ID        = ost_ctrl_id;

    generate
    if (DATA_BYTES >= 4096/MAX_BURST_LEN) begin : must_one_burst
        wire                      read_sect;

        assign out_BURST_ADDR     = sect_addr_buf;
        assign out_BURST_LEN      = sect_len_buf;
        assign out_BURST_VALID    = burst_valid;
        assign out_BURST_ID       = req_id_buf;

        assign ost_ctrl_valid     = next_sect;
        assign ost_ctrl_info      = last_sect_tmp;
        assign ost_ctrl_id        = req_id;
        assign ost_ctrl_ready     = in_CTRL_READY[req_id];

        assign next_sect          = read_sect && ost_ctrl_ready;
        assign ready_for_sect     = ~(burst_valid && ~in_BURST_READY) && req_full_n && |in_CTRL_READY;
        assign read_sect          = req_handling & ready_for_sect;
        assign read_req           = ~req_handling || ready_for_sect;

        always @(posedge clk)
        begin
            if (reset)
                burst_valid <= 1'b0;
            else if (clk_en) begin
                if (next_sect)
                    burst_valid <= 1'b1;
                else if (in_BURST_READY)
                    burst_valid <= 1'b0;
            end
        end

        // calculate remaining request, for interleaved burst handling.
        assign rem_req_pack      = {rem_req_id, {rem_req_len[LEN_WIDTH-ADDR_ALIGN-1:0], {ADDR_ALIGN{1'b1}}}, rem_req_addr};
        assign rem_req_addr_pred = ost_ctrl_ready ? {sect_cnt+1, {12{1'b0}}}  : sect_addr;
        assign rem_req_len_pred  = ost_ctrl_ready ? (beat_len - sect_len - 1) : beat_len;

        always @(posedge clk)
        begin
            if (reset) begin
                rem_req_id   <= 0;
                rem_req_addr <= 0;
                rem_req_len <= 0;
            end
            else if (clk_en) begin
                if (read_sect) begin
                    rem_req_id   <= req_id;
                    rem_req_addr <= rem_req_addr_pred;
                    rem_req_len  <= rem_req_len_pred;
                end
            end
        end

        always @(posedge clk)
        begin
            if (reset)
                rem_req_valid <= 1'b0;
            else if (clk_en) begin
                if (next_sect && last_sect_tmp)
                    rem_req_valid <= 1'b0;
                else if (req_empty_n && read_sect)
                    rem_req_valid <= 1'b1;
                else if (req_full_n)
                    rem_req_valid <= 1'b0;
            end
        end
    end
    else begin : could_multi_bursts
        reg  [ID_WIDTH-1:0]                       burst_id;
        reg  [ADDR_WIDTH - 1:0]                   burst_addr;
        wire [ADDR_WIDTH - 1:0]                   burst_addr_next;
        reg  [ADDR_WIDTH - 1:0]                   burst_addr_pred;
        reg  [7:0]                                burst_len;
        reg  [7:0]                                burst_len_pred;
        reg  [8:0]                                burst_len_pred_plus1;

        reg                                       next_req_ready;
        reg                                       sect_handling;
        reg  [11 - NUM_BEAT_WIDTH - ADDR_ALIGN:0] loop_cnt;
        reg                                       first_loop;
        reg                                       last_loop;
        wire                                      next_loop;
        wire                                      read_loop;
        wire                                      ready_for_loop;

        wire                                      last_loop_when_next_loop;
        wire                                      last_loop_when_next_sect;
        wire [7:0]                                burst_len_when_next_loop;
        wire [7:0]                                burst_len_when_next_sect;

        assign out_BURST_ADDR  = burst_addr;
        assign out_BURST_LEN   = burst_len;
        assign out_BURST_VALID = burst_valid;
        assign out_BURST_ID    = burst_id;

        assign ost_ctrl_valid  = next_loop;
        assign ost_ctrl_info   = last_loop && last_sect_buf;
        assign ost_ctrl_id     = req_id_buf;
        assign ost_ctrl_ready  = in_CTRL_READY[req_id_buf];

        assign ready_for_loop  = ~(burst_valid && ~in_BURST_READY) && req_full_n && |in_CTRL_READY; 
        assign read_loop       = sect_handling && ready_for_loop;
        assign next_loop       = read_loop & ost_ctrl_ready;

        assign next_sect       = req_handling & ready_for_sect;
        assign ready_for_sect  = ~sect_handling  || (read_loop && next_req_ready) || (next_loop && last_loop);
        assign read_req        = ~next_req_ready || ready_for_sect;

        always @(posedge clk)
        begin
            if (reset)
                burst_valid <= 1'b0;
            else if (clk_en) begin
                if (next_loop)
                    burst_valid <= 1'b1;
                else if (in_BURST_READY)
                    burst_valid <= 1'b0;
            end
        end

        always @(posedge clk)
        begin
            if (reset)
                sect_handling <= 1'b0;
            else if (clk_en) begin
                if (req_handling && ~sect_handling)
                    sect_handling <= 1'b1;
                else if (~req_handling && last_loop && next_loop)
                    sect_handling <= 1'b0;
            end
        end

        always @(posedge clk)
        begin
            if (reset) begin
                first_loop <= 1'b0;
                last_loop  <= 1'b0;
                loop_cnt   <= 0;
            end
            else if (clk_en) begin
                if (next_sect) begin
                    first_loop <= 1'b1;
                    last_loop  <= last_loop_when_next_sect;
                    loop_cnt   <= sect_len[11 - ADDR_ALIGN : NUM_BEAT_WIDTH];
                end
                else if (next_loop) begin
                    first_loop <= 1'b0;
                    last_loop  <= last_loop_when_next_loop;
                    loop_cnt   <= loop_cnt - 1;
                end
            end
        end

        assign last_loop_when_next_sect = (sect_len[11 - ADDR_ALIGN : NUM_BEAT_WIDTH] == 0); 
        assign last_loop_when_next_loop = (loop_cnt == 1);

        assign burst_addr_next = first_loop ? sect_addr_buf  : burst_addr_pred;
        assign burst_len_when_next_sect = (NUM_BEAT_WIDTH == 0)    ? 0 :
                                          last_loop_when_next_sect ? sect_len[NUM_BEAT_WIDTH - 1:0] :
                                                                     {NUM_BEAT_WIDTH{1'b1} };
        assign burst_len_when_next_loop = (NUM_BEAT_WIDTH == 0)    ? 0 :
                                          last_loop_when_next_loop ? sect_len_buf[NUM_BEAT_WIDTH - 1:0] :
                                                                     {NUM_BEAT_WIDTH{1'b1} };

        assign rem_req_pack = {rem_req_id, {rem_req_len[LEN_WIDTH-ADDR_ALIGN-1:0], {ADDR_ALIGN{1'b1}}}, rem_req_addr};

        assign rem_req_addr_pred = ost_ctrl_ready &  first_loop ? sect_addr_buf   + (burst_len_pred_plus1 << ADDR_ALIGN) :
                                   ost_ctrl_ready & ~first_loop ? burst_addr_pred + (burst_len_pred_plus1 << ADDR_ALIGN) :
                                  ~ost_ctrl_ready &  first_loop ? sect_addr_buf : 
                                                                  burst_addr_pred;

        assign rem_req_len_pred  = ost_ctrl_ready &  first_loop ? beat_len_buf - burst_len_pred_plus1 :
                                   ost_ctrl_ready & ~first_loop ? rem_req_len  - burst_len_pred_plus1 :
                                  ~ost_ctrl_ready &  first_loop ? beat_len_buf :
                                                                  rem_req_len;
    
        always @(posedge clk)
        begin
            if (reset) begin
                burst_len_pred       <= 2**NUM_BEAT_WIDTH - 1;
                burst_len_pred_plus1 <= 2**NUM_BEAT_WIDTH;
            end
            else if (clk_en) begin
                if (next_sect) begin
                    burst_len_pred       <= burst_len_when_next_sect;
                    burst_len_pred_plus1 <= burst_len_when_next_sect + 1;
                end
                else if (next_loop) begin
                    burst_len_pred       <= burst_len_when_next_loop;
                    burst_len_pred_plus1 <= burst_len_when_next_loop + 1;
                end
            end
        end

        always @(posedge clk)
        begin
            if (reset) begin
                burst_id    <= 0;
                burst_addr  <= 0;
                burst_len   <= 0;
                burst_addr_pred <= 0;
            end
            else if (clk_en) begin
                if (next_loop) begin
                    burst_id    <= req_id_buf;
                    burst_addr  <= burst_addr_next;
                    burst_len   <= burst_len_pred;
                    burst_addr_pred <= burst_addr_next + (burst_len_pred_plus1 << ADDR_ALIGN);
                end
            end
        end

        always @(posedge clk)
        begin
            if (reset) begin
                rem_req_id   <= 0;
                rem_req_addr <= 0;
                rem_req_len  <= 0;
            end
            else if (clk_en) begin
                if (read_loop) begin
                    rem_req_id   <= req_id_buf;
                    rem_req_addr <= rem_req_addr_pred;
                    rem_req_len  <= rem_req_len_pred;
                end
            end
        end

        always @(posedge clk)
        begin
            if (reset)
                next_req_ready <= 1'b0;
            else if (clk_en) begin
                if (next_req)
                    next_req_ready <= 1'b1;
                else if (next_sect)
                    next_req_ready <= 1'b0;
            end
        end

        always @(posedge clk)
        begin
            if (reset)
                rem_req_valid <= 1'b0;
            else if (clk_en) begin
                if (next_loop && last_loop && last_sect_buf)
                    rem_req_valid <= 1'b0;
                else if (next_req_ready && read_loop)
                    rem_req_valid <= 1'b1;
                else if (req_full_n)
                    rem_req_valid <= 1'b0;
            end
        end
    end
    endgenerate

endmodule

(* DowngradeIPIdentifiedWarnings="yes" *) module SSM_in_z_silu_m_axi_burst_sequential
#(parameter
    ID_WIDTH                     = 1,
    DATA_WIDTH                   = 32,
    ADDR_WIDTH                   = 32,
    LEN_WIDTH                    = 32,
    NUM_PORTS                    = 1,
    MAX_BURST_LEN                = 16
)(
    input  wire                  clk,
    input  wire                  reset,
    input  wire                  clk_en,
    input  wire [ID_WIDTH-1:0]   in_REQ_ID,
    input  wire [ADDR_WIDTH-1:0] in_REQ_ADDR,
    input  wire [LEN_WIDTH-1:0]  in_REQ_LEN,
    input  wire                  in_REQ_VALID,
    output wire [NUM_PORTS-1:0]  out_REQ_READY,
    output wire [ID_WIDTH-1:0]   out_BURST_ID,
    output wire [ADDR_WIDTH-1:0] out_BURST_ADDR,
    output wire [7:0]            out_BURST_LEN,
    output wire                  out_BURST_VALID,
    input  wire                  in_BURST_READY,
    output wire [ID_WIDTH-1:0]   out_CTRL_ID,
    output wire                  out_CTRL_INFO,
    output wire                  out_CTRL_VALID,
    input  wire [NUM_PORTS-1:0]  in_CTRL_READY
);
//------------------------Parameter----------------------
    localparam
        PACK_WIDTH      = ID_WIDTH+ADDR_WIDTH+LEN_WIDTH,
        DATA_BYTES      = DATA_WIDTH / 8,
        ADDR_ALIGN      = log2(DATA_BYTES),
        BOUNDARY_BEATS  = {12-ADDR_ALIGN{1'b1}},
        NUM_BEAT_WIDTH  = log2(MAX_BURST_LEN);
//------------------------Task and function--------------
    function integer log2;
        input integer x;
        integer n, m;
        begin
            n = 0;
            m = 1;
            while (m < x) begin
                n = n + 1;
                m = m * 2;
            end
            log2 = n;
        end
    endfunction
//------------------------Local signal-------------------
    wire [PACK_WIDTH-1:0]       req_pack_in;
    wire [PACK_WIDTH-1:0]       req_pack_out;
    wire [ID_WIDTH-1:0]         req_id_tmp;
    wire [ADDR_WIDTH-1:0]       req_addr_tmp;
    wire [LEN_WIDTH-1:0]        req_len_tmp;

    wire                        req_full_n;
    wire                        req_empty_n;
    wire                        write_req;
    wire                        read_req;
    wire                        next_req;

    wire [LEN_WIDTH-1:0]        end_addr_tmp;
    reg  [ADDR_WIDTH - 1:0]     start_addr;
    wire [ADDR_WIDTH-1:0]       start_addr_tmp;
    wire [ADDR_WIDTH - 1:0]     sect_addr;
    reg  [ADDR_WIDTH - 1:0]     sect_addr_buf;
    reg  [ID_WIDTH-1:0]         req_id;
    reg  [ID_WIDTH-1:0]         req_id_buf;
    reg                         req_handling;

    reg  [11 - ADDR_ALIGN:0]    start_to_4k;
    reg  [11 - ADDR_ALIGN:0]    end_from_4k;
    wire [11 - ADDR_ALIGN:0]    sect_len;
    reg  [11 - ADDR_ALIGN:0]    sect_len_buf;
    reg  [11 - ADDR_ALIGN:0]    beat_total;
    wire [11 - ADDR_ALIGN:0]    beat_total_tmp;

    wire [ADDR_WIDTH-13:0]      sect_cnt;
    reg  [ADDR_WIDTH/2-1:0]     sect_cnt_msb;
    reg  [ADDR_WIDTH/2-13:0]    sect_cnt_lsb;
    reg                         sect_cnt_carry;

    reg  [LEN_WIDTH-13:0]       sect_total;
    reg  [LEN_WIDTH-13:0]       sect_total_buf;
    wire [LEN_WIDTH-13:0]       sect_total_tmp;
    wire                        ready_for_sect;
    
    reg                         single_sect;
    wire                        single_sect_tmp;
    (* dont_touch = "yes" *)reg first_sect;
    reg                         last_sect;
    wire                        last_sect_tmp;
    reg                         last_sect_buf;
    wire                        next_sect;

    reg                         burst_valid;

    wire [ID_WIDTH-1:0]         ost_ctrl_id;
    wire                        ost_ctrl_info;
    wire                        ost_ctrl_valid;
    wire                        ost_ctrl_ready;

//------------------------Instantiation------------------
    SSM_in_z_silu_m_axi_reg_slice #(
        .DATA_WIDTH     (PACK_WIDTH)
    ) rs_req (
        .clk            (clk),
        .reset          (reset),
        .s_data         (req_pack_in),
        .s_valid        (write_req),
        .s_ready        (req_full_n),
        .m_data         (req_pack_out),
        .m_valid        (req_empty_n),
        .m_ready        (read_req));
    
//------------------------Body--------------------------- 

    assign out_REQ_READY = {NUM_PORTS{req_full_n}};
    assign req_pack_in   = {in_REQ_ID, in_REQ_LEN, in_REQ_ADDR};
    assign write_req     = in_REQ_VALID;

    assign req_id_tmp    = req_pack_out[PACK_WIDTH-1  : ADDR_WIDTH+LEN_WIDTH];
    assign req_len_tmp   = req_pack_out[ADDR_WIDTH+LEN_WIDTH-1 : ADDR_WIDTH];
    assign req_addr_tmp  = req_pack_out[ADDR_WIDTH-1  : 0];

    assign start_addr_tmp = {req_addr_tmp[ADDR_WIDTH-1:ADDR_ALIGN], {ADDR_ALIGN{1'b0}}};
    assign end_addr_tmp   = (req_len_tmp + req_addr_tmp[11:0]);
    assign beat_total_tmp = (req_len_tmp[11:0] + req_addr_tmp[ADDR_ALIGN-1:0]) >> ADDR_ALIGN;

    assign read_req      = last_sect_tmp & next_sect | ~req_handling;
    assign next_req      = read_req & req_empty_n;

    always @(posedge clk)
    begin
        if (reset) begin
            req_id      <= 0;
            start_addr  <= 0;
            beat_total  <= 0;
            sect_total  <= 0;
            end_from_4k <= 0;
            start_to_4k <= 0;
        end
        else if (clk_en) begin
            if (next_req) begin
                req_id      <= req_id_tmp;
                start_addr  <= start_addr_tmp;
                beat_total  <= beat_total_tmp;
                sect_total  <= end_addr_tmp[LEN_WIDTH-1:12];
                end_from_4k <= end_addr_tmp[11:ADDR_ALIGN];
                start_to_4k <= ~(req_addr_tmp[11:ADDR_ALIGN]);
            end
        end
    end

    always @(posedge clk)
    begin
        if (reset)
            req_handling <= 1'b0;
        else if (clk_en) begin
            if (next_req)
                req_handling <= 1'b1;
            else if (~req_empty_n && last_sect_tmp & next_sect)
                req_handling <= 1'b0;
        end
    end

    // 4k boundary
    assign single_sect_tmp = (req_len_tmp[LEN_WIDTH-1:12] == 0) && !end_addr_tmp[12];

    assign last_sect_tmp  = single_sect || last_sect;

    assign sect_total_tmp = first_sect ? sect_total : sect_total_buf;

    assign sect_addr = (first_sect) ? start_addr : {sect_cnt, {12{1'b0}}};
    
    assign sect_len  =  single_sect               ? beat_total :
                      ( first_sect && ~last_sect) ? start_to_4k :
                      (~first_sect &&  last_sect) ? end_from_4k :
                                                    BOUNDARY_BEATS;

   always @(posedge clk)
    begin
        if (reset) begin
            first_sect <= 1'b0;
            last_sect <= 1'b0;
            single_sect <= 1'b0;
        end
        else if (clk_en) begin
            if (next_req) begin
                first_sect <= 1'b1;
                last_sect <= 1'b0;
                single_sect <= single_sect_tmp;
            end
            else if (next_sect) begin
                first_sect <= 1'b0;
                last_sect <= (sect_total_tmp == 1);
                single_sect <= single_sect;
            end
        end
    end

    // pipelined logic for sect_cnt
    // msb and lsb are handled separately to avoid long carry chain
    assign sect_cnt  = {sect_cnt_msb, sect_cnt_lsb};

    always @(posedge clk)
    begin
        if (reset) begin
            // sect_cnt <= 0;
            sect_cnt_carry <= 1'b0;
            sect_cnt_msb <= 0;
            sect_cnt_lsb <= 0;
        end
        else if (clk_en) begin
            if (next_req) begin
                // sect_cnt <= req_addr_tmp[ADDR_WIDTH-1:12];
                sect_cnt_carry <= (start_addr_tmp[ADDR_WIDTH/2-1:12] == (2**(ADDR_WIDTH/2-12) - 1));
                sect_cnt_lsb <= start_addr_tmp[ADDR_WIDTH/2-1:12];
                sect_cnt_msb <= start_addr_tmp[ADDR_WIDTH-1:ADDR_WIDTH/2];
            end
            else if (next_sect) begin
                // sect_cnt <= sect_cnt + 1;
                sect_cnt_carry <= (sect_cnt_lsb == (2**(ADDR_WIDTH/2-12) - 2));
                sect_cnt_msb <= sect_cnt_msb + sect_cnt_carry;
                sect_cnt_lsb <= sect_cnt_lsb + 1;
            end
        end
    end

    always @(posedge clk)
    begin
        if (reset) begin
            req_id_buf     <= 0;
            sect_addr_buf  <= 0;
            sect_len_buf   <= 0;
            last_sect_buf  <= 1'b0;
            sect_total_buf <= 0;
        end
        else if (clk_en) begin
            if (next_sect) begin
                req_id_buf     <= req_id;
                sect_addr_buf  <= sect_addr;
                sect_len_buf   <= sect_len;
                last_sect_buf  <= last_sect_tmp;
                sect_total_buf <= sect_total_tmp - 1;
            end
        end
    end

    assign out_CTRL_VALID     = ost_ctrl_valid;
    assign out_CTRL_INFO      = ost_ctrl_info;
    assign out_CTRL_ID        = ost_ctrl_id;

    generate
    if (DATA_BYTES >= 4096/MAX_BURST_LEN) begin : must_one_burst
        wire                   read_sect;

        assign out_BURST_ADDR  = sect_addr_buf;
        assign out_BURST_LEN   = sect_len_buf;
        assign out_BURST_VALID = burst_valid;
        assign out_BURST_ID    = req_id_buf;

        assign ost_ctrl_valid  = next_sect;
        assign ost_ctrl_info   = last_sect_tmp;
        assign ost_ctrl_id     = req_id;
        assign ost_ctrl_ready  = in_CTRL_READY[req_id];

        assign next_sect       = read_sect && ost_ctrl_ready;
        assign read_sect       = req_handling && ready_for_sect;
        assign ready_for_sect  = ~(burst_valid && ~in_BURST_READY);

        always @(posedge clk)
        begin
            if (reset)
                burst_valid <= 1'b0;
            else if (clk_en) begin
                if (next_sect)
                    burst_valid <= 1'b1;
                else if (in_BURST_READY)
                    burst_valid <= 1'b0;
            end
        end
    
    end
    else begin : could_multi_bursts
        reg  [ADDR_WIDTH-13:0]                    burst_addr_base;
        reg  [ID_WIDTH-1:0]                       burst_id;
        reg  [11:0]                               burst_addr;
        wire [11:0]                               burst_addr_next;
        wire [11 - NUM_BEAT_WIDTH - ADDR_ALIGN:0] burst_addr_cnt;
        wire [NUM_BEAT_WIDTH + ADDR_ALIGN - 1:0]  burst_addr_ofs;
        reg  [7:0]                                burst_len;
        wire [7:0]                                burst_len_next;

        reg                                       sect_handling;
        reg  [11 - NUM_BEAT_WIDTH - ADDR_ALIGN:0] loop_cnt;
        reg                                       first_loop;
        reg                                       last_loop;
        wire                                      next_loop;
        wire                                      read_loop;
        wire                                      ready_for_loop;

        assign out_BURST_ADDR  = {burst_addr_base, burst_addr};
        assign out_BURST_LEN   = burst_len;
        assign out_BURST_VALID = burst_valid;
        assign out_BURST_ID    = burst_id;

        assign ost_ctrl_valid  = next_loop;
        assign ost_ctrl_info   = last_loop && last_sect_buf;
        assign ost_ctrl_id     = req_id_buf;
        assign ost_ctrl_ready  = in_CTRL_READY[req_id_buf];
        
        assign ready_for_loop  = ~(burst_valid && ~in_BURST_READY);
        assign read_loop       = sect_handling && ready_for_loop;
        assign next_loop       = read_loop && ost_ctrl_ready;

        assign next_sect       = req_handling && ready_for_sect;
        assign ready_for_sect  = ~sect_handling || (last_loop && next_loop);

        always @(posedge clk)
        begin
            if (reset)
                burst_valid <= 1'b0;
            else if (clk_en) begin
                if (next_loop)
                    burst_valid <= 1'b1;
                else if (in_BURST_READY)
                    burst_valid <= 1'b0;
            end
        end

        always @(posedge clk)
        begin
            if (reset)
                sect_handling <= 1'b0;
            else if (clk_en) begin
                if (req_handling && ~sect_handling)
                    sect_handling <= 1'b1;
                else if (~req_handling && last_loop && next_loop)
                    sect_handling <= 1'b0;
            end
        end

        always @(posedge clk)
        begin
            if (reset) begin
                first_loop <= 1'b0;
                last_loop <= 1'b0;
                loop_cnt <= 0;
            end
            else if (clk_en) begin
                if (next_sect) begin
                    first_loop <= 1'b1;
                    last_loop <= (sect_len[11 - ADDR_ALIGN : NUM_BEAT_WIDTH] == 0);
                    loop_cnt <= sect_len[11 - ADDR_ALIGN : NUM_BEAT_WIDTH];
                end
                else if (next_loop) begin
                    first_loop <= 1'b0;
                    last_loop <= (loop_cnt == 1);
                    loop_cnt <= loop_cnt - 1;
                end
            end
        end

        assign burst_addr_cnt  = burst_addr[11:NUM_BEAT_WIDTH+ADDR_ALIGN] + 1;
        assign burst_addr_ofs  = burst_addr[NUM_BEAT_WIDTH+ADDR_ALIGN-1:0];
        assign burst_addr_next = first_loop ? sect_addr_buf[11:0] : {burst_addr_cnt, burst_addr_ofs};
        assign burst_len_next  = (NUM_BEAT_WIDTH == 0) ? 0 :
                                 last_loop             ? sect_len_buf[NUM_BEAT_WIDTH - 1:0] :
                                                         { NUM_BEAT_WIDTH{1'b1} };

        always @(posedge clk)
        begin
            if (reset) begin
                burst_addr_base <= 0;
                burst_id   <= 0;
                burst_addr <= 0;
                burst_len  <= 0;
            end
            else if (clk_en) begin
                if (next_loop) begin
                    burst_addr_base <= sect_addr_buf[ADDR_WIDTH-1:12];
                    burst_id   <= req_id_buf;
                    burst_addr <= burst_addr_next;
                    burst_len  <= burst_len_next;
                end
            end
        end

    end
    endgenerate

endmodule




(* DowngradeIPIdentifiedWarnings="yes" *) module SSM_in_z_silu_m_axi_reg_slice
#(parameter
    DATA_WIDTH = 8
) (
    // system signals
    input  wire                  clk,
    input  wire                  reset,
    // slave side
    input  wire [DATA_WIDTH-1:0] s_data,
    input  wire                  s_valid,
    output wire                  s_ready,
    // master side
    output wire [DATA_WIDTH-1:0] m_data,
    output wire                  m_valid,
    input  wire                  m_ready
);
//------------------------Parameter----------------------
    // state
    localparam [1:0]
        ZERO = 2'b10,
        ONE  = 2'b11,
        TWO  = 2'b01;
//------------------------Local signal-------------------
    reg  [DATA_WIDTH-1:0] data_p1;
    reg  [DATA_WIDTH-1:0] data_p2;
    wire         load_p1;
    wire         load_p2;
    wire         load_p1_from_p2;
    reg          s_ready_t;
    reg  [1:0]   state;
    reg  [1:0]   next;
//------------------------Body---------------------------
    assign s_ready = s_ready_t;
    assign m_data  = data_p1;
    assign m_valid = state[0];

    assign load_p1 = (state == ZERO && s_valid) ||
                    (state == ONE && s_valid && m_ready) ||
                    (state == TWO && m_ready);
    assign load_p2 = s_valid & s_ready;
    assign load_p1_from_p2 = (state == TWO);

    // data_p1
    always @(posedge clk) begin
        if (load_p1) begin
            if (load_p1_from_p2)
                data_p1 <= data_p2;
            else
                data_p1 <= s_data;
        end
    end

    // data_p2
    always @(posedge clk) begin
        if (load_p2) data_p2 <= s_data;
    end

    // s_ready_t
    always @(posedge clk) begin
        if (reset)
            s_ready_t <= 1'b0;
        else if (state == ZERO)
            s_ready_t <= 1'b1;
        else if (state == ONE && next == TWO)
            s_ready_t <= 1'b0;
        else if (state == TWO && next == ONE)
            s_ready_t <= 1'b1;
    end

    // state
    always @(posedge clk) begin
        if (reset)
            state <= ZERO;
        else
            state <= next;
    end

    // next
    always @(*) begin
        case (state)
            ZERO:
                if (s_valid & s_ready)
                    next = ONE;
                else
                    next = ZERO;
            ONE:
                if (~s_valid & m_ready)
                    next = ZERO;
                else if (s_valid & ~m_ready)
                    next = TWO;
                else
                    next = ONE;
            TWO:
                if (m_ready)
                    next = ONE;
                else
                    next = TWO;
            default:
                next = ZERO;
        endcase
    end
endmodule


(* DowngradeIPIdentifiedWarnings="yes" *) module SSM_in_z_silu_m_axi_fifo
#(parameter
    MEM_STYLE   = "shiftreg",
    DATA_WIDTH = 32,
    ADDR_WIDTH = 5,
    DEPTH      = 32
) (
    // system signal
    input  wire                  clk,
    input  wire                  reset,
    input  wire                  clk_en,
    // write
    output wire                  if_full_n,
    input  wire                  if_write,
    input  wire [DATA_WIDTH-1:0] if_din,
    // read
    output wire                  if_empty_n,
    input  wire                  if_read,
    output wire [DATA_WIDTH-1:0] if_dout,
    output wire [ADDR_WIDTH:0]   if_num_data_valid);

//------------------------Local signal-------------------

    wire                  push;
    wire                  pop;
    reg                   full_n = 1'b1;
    reg                   empty_n = 1'b0;
    reg                   dout_vld = 1'b0;
//------------------------Body---------------------------

    generate if (DEPTH == 0) begin
        assign if_num_data_valid = if_write;
        assign if_full_n  = if_read;
        assign if_empty_n = if_write;
        assign if_dout = if_din;

    end else if (DEPTH == 1) begin
        reg [DATA_WIDTH-1:0] dout_reg;

        assign if_num_data_valid = dout_vld;
        assign if_full_n  = !dout_vld;
        assign if_empty_n = dout_vld;
        assign if_dout = dout_reg;
        assign push = !dout_vld & if_write;
        assign pop  = dout_vld & if_read;

        always @(posedge clk)
        begin
            if (reset == 1'b1)
                dout_reg <= 0;
            else if (clk_en) begin
                if (push)
                    dout_reg <= if_din;
            end
        end

        // dout_vld
        always @(posedge clk) begin
            if (reset == 1'b1)
                dout_vld <= 1'b0;
            else if (clk_en)
                if (push)
                    dout_vld <= 1'b1;
                else if (pop)
                    dout_vld <= 1'b0;
        end
    
    end else if (DEPTH > 1) begin
        reg  [ADDR_WIDTH-1:0] raddr = {ADDR_WIDTH{1'b0}};
        reg  [ADDR_WIDTH-1:0] waddr = {ADDR_WIDTH{1'b0}};
        reg  [ADDR_WIDTH:0]   mOutPtr = {ADDR_WIDTH+1{1'b0}};
        reg  [ADDR_WIDTH:0]   num_data_cnt = {ADDR_WIDTH+1{1'b0}};
        wire                  pop_dout;

        assign if_num_data_valid = dout_vld ? num_data_cnt : {ADDR_WIDTH+1{1'b0}};
        assign if_full_n  = full_n;
        assign if_empty_n = dout_vld;
        assign push = full_n & if_write;
        assign pop  = empty_n & (if_read | ~dout_vld);
        assign pop_dout = dout_vld & if_read;

        if (MEM_STYLE == "shiftreg") begin
            SSM_in_z_silu_m_axi_srl
            #(  .DATA_WIDTH     (DATA_WIDTH),
                .ADDR_WIDTH     (ADDR_WIDTH),
                .DEPTH          (DEPTH))
            U_fifo_srl(
                .clk            (clk),
                .reset          (reset),
                .clk_en         (clk_en),
                .we             (push),
                .din            (if_din),
                .raddr          (raddr),
                .re             (pop),
                .dout           (if_dout)
            );
            // raddr
            always @(posedge clk) begin
                if (reset == 1'b1)
                    raddr <= {ADDR_WIDTH+1{1'b0}};
                else if (clk_en) begin
                    if (push & ~pop & empty_n)
                        raddr <= raddr + 1'b1;
                    else if (~push & pop && raddr != 0)
                        raddr <= raddr - 1'b1;
                end
            end
        end else begin
            wire [ADDR_WIDTH-1:0] wnext;
            wire [ADDR_WIDTH-1:0] rnext;

            SSM_in_z_silu_m_axi_mem
            #(  .MEM_STYLE      (MEM_STYLE),
                .DATA_WIDTH     (DATA_WIDTH),
                .ADDR_WIDTH     (ADDR_WIDTH),
                .DEPTH          (DEPTH))
            U_fifo_mem(
                .clk            (clk),
                .reset          (reset),
                .clk_en         (clk_en),
                .we             (push),
                .waddr          (waddr),
                .din            (if_din),
                .raddr          (raddr),
                .re             (pop),
                .dout           (if_dout)
            );

            assign wnext =  !push                ? waddr :
                            (waddr == DEPTH - 2) ? 1'b0  :
                            waddr + 1'b1;
            assign rnext =  !pop                 ? raddr :
                            (raddr == DEPTH - 2) ? 1'b0  :
                            raddr + 1'b1;

            // waddr
            always @(posedge clk) begin
                if (reset == 1'b1)
                    waddr <= {ADDR_WIDTH{1'b0}};
                else if (clk_en)
                    waddr <= wnext;
            end

            // raddr
            always @(posedge clk) begin
                if (reset == 1'b1)
                    raddr <= {ADDR_WIDTH{1'b0}};
                else if (clk_en)
                    raddr <= rnext;
            end
        end

        // mOutPtr
        always @(posedge clk) begin
            if (reset == 1'b1)
                mOutPtr <= {ADDR_WIDTH+1{1'b0}};
