        end

        // empty_n
        always @(posedge clk)
        begin
            if (reset == 1'b1)
                empty_n <= 1'b0;
            else if (clk_en) begin
                if (push & ~pop)
                    empty_n <= 1'b1;
                else if ((~push & pop) && (mOutPtr == 1))
                    empty_n <= 1'b0;
            end
        end

        // dout_vld
        always @(posedge clk) begin
            if (reset == 1'b1)
                dout_vld <= 1'b0;
            else if (clk_en)
                if (pop)
                    dout_vld <= 1'b1;
